const body = $('Webhook').first().json.body;
const leadData = $('Get Lead').first().json;
const folderPath = (leadData.fields ? leadData.fields['Dropbox Folder Path'] : leadData['Dropbox Folder Path']) || '_CoCard/_Leads/unknown';

const files = body.files || {};
const results = [];

for (const [key, file] of Object.entries(files)) {
  if (!file || !file.data || !file.name) continue;
  const buffer = Buffer.from(file.data, 'base64');
  const binary = await this.helpers.prepareBinaryData(buffer, file.name);
  results.push({
    json: { dropboxPath: ('/' + folderPath + '/' + file.name).replace('//', '/') },
    binary: { data: binary }
  });
}

return results;

const body = $('Webhook').first().json.body;
const leadData = $('Get Lead').first().json;
const folderPath = (leadData.fields ? leadData.fields['Dropbox Folder Path'] : leadData['Dropbox Folder Path']) || '_CoCard/_Leads/unknown';

const sensitive = {
  leadId:     body.leadId,
  captured:   new Date().toISOString(),
  ein:        body.ein        || '',
  owner1_dob: body.owner1_dob || '',
  owner1_ssn: body.owner1_ssn || '',
  owner2_dob: body.owner2_dob || '',
  owner2_ssn: body.owner2_ssn || '',
  owner3_dob: body.owner3_dob || '',
  owner3_ssn: body.owner3_ssn || ''
};

const buffer = Buffer.from(JSON.stringify(sensitive, null, 2), 'utf8');
const binary = await this.helpers.prepareBinaryData(buffer, 'sensitive-data.json', 'application/json');

return [{
  json: { dropboxPath: ('/' + folderPath + '/sensitive-data.json').replace('//', '/') },
  binary: { data: binary }
}];
